using System.IO;
using System.Reflection;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Locates and reads source files that live next to the application project
/// (e.g. <c>Program.cs</c>, <c>Controllers/FilesController.cs</c>,
/// <c>README.md</c>) from within a test running out of the compiled
/// <c>bin/Debug/...</c> output directory.
///
/// <para>
/// The root is discovered by walking up from
/// <see cref="AppContext.BaseDirectory"/> until a directory containing
/// <c>TestProject.csproj</c> is found. A relative path is then resolved
/// against that root. This mirrors the approach already used by
/// <c>ProgramWiringTests.LoadProgramSource</c> but is shared/reusable so
/// security wiring tests, controller doc-comment tests and README tests do
/// not each reimplement the directory walk.
/// </para>
/// </summary>
public static class SourceFileLoader
{
    /// <summary>
    /// Returns the directory containing <c>TestProject.csproj</c>, found by
    /// walking up from the test assembly's output directory. Throws if it
    /// cannot be located.
    /// </summary>
    public static string FindProjectRoot()
    {
        var dir = new DirectoryInfo(AppContext.BaseDirectory);
        while (dir is not null)
        {
            if (File.Exists(Path.Combine(dir.FullName, "TestProject.csproj")))
            {
                return dir.FullName;
            }

            dir = dir.Parent;
        }

        throw new FileNotFoundException(
            "Could not locate the project root (folder containing TestProject.csproj) " +
            "by walking up from the test output directory (" + AppContext.BaseDirectory + ").");
    }

    /// <summary>
    /// Loads the source file at <paramref name="relativeSegments"/> relative
    /// to the project root (the folder containing <c>TestProject.csproj</c>).
    /// Throws with a descriptive message if the file is not found.
    /// </summary>
    /// <param name="relativeSegments">
    /// The path parts under the project root, e.g.
    /// <c>("Controllers", "FilesController.cs")</c> or
    /// <c>("Program.cs",)</c> or <c>("README.md",)</c>.</param>
    public static string LoadAdjacent(params string[] relativeSegments)
    {
        var root = FindProjectRoot();
        var fullPath = Path.Combine(root, Path.Combine(relativeSegments));

        if (!File.Exists(fullPath))
        {
            throw new FileNotFoundException(
                $"Expected source file not found at '{fullPath}' (resolved from project " +
                $"root '{root}').", fullPath);
        }

        return File.ReadAllText(fullPath);
    }
}

using System;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Documentation-accuracy tests for <c>README.md</c>.
///
/// <para>
/// The <c>FileService</c> home directory is created <b>lazily</b>: directory
/// creation is wrapped in a <c>Lazy&lt;string&gt;</c> (<c>_rootLazy</c>) that
/// is materialized only on the first access of the <c>Root</c> property — i.e.
/// on the first file-system operation, not at construction or DI resolution.
/// The behavioral contract is pinned down by
/// <see cref="Services.FileServiceTests.Constructor_DoesNotCreateRootDirectory_BeforeFirstUse"/>
/// and its siblings (the directory must NOT exist after construction, and a
/// misconfigured path must surface on first use rather than at startup).
/// </para>
///
/// <para>
/// These tests guard the corresponding sentence in the README's
/// <c>## Configuration</c> section so the prose cannot drift back to the
/// pre-refactor claim that the folder is "created automatically on startup"
/// (which described the legacy eager <c>Directory.CreateDirectory(root)</c>
/// call in the constructor). They parse <c>README.md</c> directly, mirroring
/// the source-parsing approach used by <see cref="ProgramWiringTests"/>.
/// </para>
/// </summary>
public class ReadmeDocumentationTests
{
    private static readonly string ReadmeSource =
        SourceFileLoader.LoadAdjacent("README.md");

    /// <summary>
    /// The README must describe the home-directory folder as being created on
    /// first use (lazily), matching the <c>FileService</c> implementation.
    /// Asserting the key phrases "first use" and "lazily" keeps the test
    /// resilient to minor rephrasing while still failing if the wording
    /// regresses to eager/startup creation.
    /// </summary>
    [Fact]
    public void Readme_ConfigurationSection_DescribesLazyFolderCreation()
    {
        Assert.Contains("first use", ReadmeSource, StringComparison.Ordinal);
        Assert.Contains("lazily", ReadmeSource, StringComparison.Ordinal);
    }

    /// <summary>
    /// The README must explain the observable consequence of lazy creation —
    /// that a misconfigured path surfaces on the first request rather than at
    /// startup. This is the user-facing behavior the
    /// <c>Constructor_MisconfiguredHomeDirectory_DoesNotThrowUntilFirstUse</c>
    /// test proves at the code level, and the documentation must match it.
    /// </summary>
    [Fact]
    public void Readme_ConfigurationSection_StatesMisconfigurationSurfacesOnFirstRequest()
    {
        Assert.Contains("first request", ReadmeSource, StringComparison.Ordinal);
        Assert.Contains("rather than at startup", ReadmeSource, StringComparison.Ordinal);
    }

    /// <summary>
    /// The pre-refactor claim that the folder is "created automatically on
    /// startup" must be gone from the README. That wording described the old
    /// eager constructor call and is now inaccurate; leaving it in would
    /// mislead users about when misconfiguration or disk errors surface. This
    /// test fails the moment the stale sentence is reintroduced.
    /// </summary>
    [Fact]
    public void Readme_ConfigurationSection_DoesNotClaimCreationOnStartup()
    {
        Assert.DoesNotContain("created automatically on startup", ReadmeSource, StringComparison.Ordinal);
    }
}

using System.Text;
using Microsoft.AspNetCore.Http;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Factory for creating <see cref="IFormFile"/> instances from in-memory
/// string content for use in test arrangements. This consolidates three
/// byte-identical private copies that were previously duplicated across
/// test classes into a single reusable utility.
/// </summary>
public static class FormFileFactory
{
    /// <summary>
    /// Creates an <see cref="IFormFile"/> whose content is the UTF-8 encoding
    /// of <paramref name="content"/>. The <see cref="IFormFile.FileName"/> is
    /// set to <paramref name="fileName"/>, the form field name is the literal
    /// <c>"file"</c>, and headers are left unpopulated (the
    /// <see cref="IFormFile.ContentDisposition"/> getter will throw).
    /// </summary>
    /// <param name="fileName">The file name exposed by the uploaded file.</param>
    /// <param name="content">The textual content, encoded as UTF-8 bytes.</param>
    /// <returns>A new <see cref="IFormFile"/> backed by a <see cref="MemoryStream"/>.</returns>
    public static IFormFile CreateFormFile(string fileName, string content)
    {
        var bytes = Encoding.UTF8.GetBytes(content);
        var stream = new MemoryStream(bytes);
        return new FormFile(stream, 0, bytes.Length, "file", fileName);
    }
}

using System.Collections.Concurrent;
using System.Text;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Models;
using TestProject.Services;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Services;

/// <summary>
/// Functional tests for <see cref="FileService"/>. Each test runs against a
/// unique temporary content root so that tests are fully independent and
/// never touch the real file system outside a scratch directory.
///
/// The service computes its home root once, at construction time, as
/// <c>Path.GetFullPath(Path.Combine(env.ContentRootPath, options.HomeDirectory))</c>.
/// Directory creation is deferred (lazy) until first use, so these tests
/// trigger an operation before asserting the directory exists on disk. Every
/// operation must funnel inputs through a path-safety check so that paths
/// escaping the home root throw <see cref="ArgumentException"/>.
/// </summary>
public class FileServiceTests : IDisposable
{
    private readonly string _contentRoot;

    public FileServiceTests()
    {
        _contentRoot = Directory.CreateTempSubdirectory("fs_test_").FullName;
    }

    public void Dispose()
    {
        try
        {
            Directory.Delete(_contentRoot, recursive: true);
        }
        catch
        {
            // Best effort cleanup; temp dirs may already be gone.
        }
    }

    // Builds a fresh service whose home directory lives under the per-test
    // content root. Returns the absolute, normalized root the service should
    // be treating as its sandbox.
    private (FileService service, string root) CreateService(string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = _contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(_contentRoot, homeDirectory));
        return (service, root);
    }

    // Builds the directory chain {baseDir}/d1/d2/.../d{levels}, creating every
    // intermediate directory along the way, and returns the deepest directory
    // path. `levels` is the number of nested directories beneath baseDir, so a
    // copy of baseDir recurses to depth == levels.
    private static string CreateNestedChain(string baseDir, int levels)
    {
        var current = baseDir;
        for (var i = 1; i <= levels; i++)
        {
            current = Path.Combine(current, $"d{i}");
        }
        Directory.CreateDirectory(current);
        return current;
    }

    // =====================================================================
    // Constructor / root computation
    // =====================================================================

    [Fact]
    public void Constructor_CreatesRootDirectory_WhenItDoesNotExist()
    {
        var home = "BrandNewHome";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: it happens on first use, not in the
        // constructor. Trigger initialization before asserting existence.
        service.ResolveFullPath("");

        Assert.True(Directory.Exists(root));
        Assert.Equal(expectedRoot, root);
    }

    [Fact]
    public void Constructor_SupportsNestedHomeDirectoryPath()
    {
        var home = "Data/Files";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: trigger initialization (which must create
        // the full nested path) before asserting existence.
        service.ResolveFullPath("");

        Assert.Equal(expectedRoot, root);
        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void Constructor_NullHomeDirectory_DefaultsToHome()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
        var options = Options.Create(new FileServiceOptions { HomeDirectory = null! });

        var service = new FileService(options, env);

        var expected = Path.GetFullPath(Path.Combine(_contentRoot, "Home"));
        // ResolveFullPath triggers lazy initialization, materializing the
        // default "Home" directory before we assert its existence.
        Assert.Equal(expected, service.ResolveFullPath(""));
        Assert.True(Directory.Exists(expected));
    }

    // =====================================================================
    // Lazy initialization of the home root
    //
    // Two complementary flavors of test live here:
    //   1. The *negative* (lazy-specific) characterization below — the home
    //      directory must NOT exist on disk immediately after construction.
    //      This is what distinguishes lazy creation from the legacy eager
    //      `Directory.CreateDirectory(root)` that ran in the constructor, and
    //      it is the observable behavior the README's Configuration section
    //      documents ("created automatically on first use (lazily), ... so a
    //      misconfigured path surfaces on the first request rather than at
    //      startup"). These tests FAIL the moment creation moves back into
    //      the constructor, which would also make the README wording stale.
    //   2. The *positive* (agnostic) characterization further down — the
    //      directory MUST exist after the first operation, regardless of
    //      whether creation happens eagerly or lazily.
    // =====================================================================

    /// <summary>
    /// The home directory must NOT be materialized by the constructor. Root
    /// creation is deferred to first use via the lazy value factory, so
    /// constructing the service — equivalent to DI resolution at startup —
    /// has no filesystem side effects. This is the negative half of the lazy
    /// contract and is the assertion that proves the README's old "created
    /// automatically on startup" wording was wrong: an eager constructor
    /// that called <c>Directory.CreateDirectory(root)</c> would make this
    /// test fail.
    /// </summary>
    [Fact]
    public void Constructor_DoesNotCreateRootDirectory_BeforeFirstUse()
    {
        var home = "EagerCheckFlat";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, _) = CreateService(home);

        // No file-system operation has been invoked yet, so the home root
        // must not exist on disk. Constructing the service alone must not
        // touch the disk.
        Assert.False(Directory.Exists(expectedRoot));

        // Sanity check that the same root DOES get created on first use, so
        // this test cannot pass vacuously (e.g. due to an uncreatable path).
        service.ResolveFullPath("");
        Assert.True(Directory.Exists(expectedRoot));
    }

    /// <summary>
    /// A nested home directory (e.g. <c>"Data/Files"</c>) must not have any of
    /// its ancestor segments created by the constructor either. Lazy
    /// creation means neither the intermediate <c>Data</c> directory nor the
    /// leaf <c>Data/Files</c> exists until the first operation targets the
    /// root. This guards against an eager constructor whose
    /// <c>Directory.CreateDirectory</c> would materialize the whole chain at
    /// startup.
    /// </summary>
    [Fact]
    public void Constructor_DoesNotCreateNestedHomeDirectory_BeforeFirstUse()
    {
        var home = "EagerCheckNested/Deep";
        var parentSegment = Path.GetFullPath(Path.Combine(_contentRoot, "EagerCheckNested"));
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(parentSegment));
        Assert.False(Directory.Exists(expectedRoot));

        var (service, _) = CreateService(home);

        // Neither the intermediate nor the leaf directory should exist yet.
        Assert.False(Directory.Exists(parentSegment));
        Assert.False(Directory.Exists(expectedRoot));

        // First use materializes the entire nested chain in one step.
        service.ResolveFullPath("");
        Assert.True(Directory.Exists(parentSegment));
        Assert.True(Directory.Exists(expectedRoot));
    }

    /// <summary>
    /// A misconfigured home directory (here, one containing an illegal null
    /// character) must NOT surface at construction time. The path is only
    /// resolved inside the lazy value factory, so the error is deferred to
    /// the first file-system operation that touches <c>Root</c>. This is the
    /// "a misconfigured path surfaces on the first request rather than at
    /// startup" half of the README's lazy-creation wording: an eager
    /// constructor that resolved and created the path up front would throw
    /// here instead of on first use. The null byte is the only invalid-path
    /// character that <see cref="Path.GetFullPath"/> rejects on every
    /// platform (on Linux, characters like <c>&lt;&gt;</c> and <c>:</c> are
    /// legal), so it is used for cross-platform determinism.
    /// </summary>
    [Fact]
    public void Constructor_MisconfiguredHomeDirectory_DoesNotThrowUntilFirstUse()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
        var options = Options.Create(new FileServiceOptions { HomeDirectory = "bad\0path" });

        // Construction must succeed: the bad path has not been resolved yet.
        var service = new FileService(options, env);
        Assert.NotNull(service);

        // The misconfiguration surfaces on first use, not at startup / DI
        // resolution.
        Assert.Throws<ArgumentException>(() => service.ResolveFullPath(""));
    }

    /// <summary>
    /// With lazy initialization, every public entry point that resolves a
    /// path must materialize the home directory on first use. These checks
    /// are written so they stay green whether the directory is created in the
    /// constructor (legacy) or on first access (lazy): in both cases the
    /// directory must exist after the call returns.
    /// </summary>
    [Theory]
    [InlineData("Resolve")]
    [InlineData("Browse")]
    [InlineData("Search")]
    public void LazyInit_CreatesRootDirectory_OnFirstMethodCall(string entryPoint)
    {
        var (service, root) = CreateService($"LazyHome_{entryPoint}");

        switch (entryPoint)
        {
            case "Resolve":
                service.ResolveFullPath("");
                break;
            case "Browse":
                service.Browse("");
                break;
            case "Search":
                service.Search("anything", "");
                break;
            default:
                throw new ArgumentException($"Unknown entry point: {entryPoint}");
        }

        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void LazyInit_IsSafe_UnderConcurrentFirstAccess()
    {
        var (service, root) = CreateService();

        // Hammer the first-access path from many threads at once. With
        // LazyThreadSafetyMode.ExecutionAndPublication the value factory must
        // run exactly once and no caller should observe an exception.
        var exceptions = new ConcurrentQueue<Exception>();

        Parallel.For(0, 32, _ =>
        {
            try
            {
                service.Browse("");
            }
            catch (Exception ex)
            {
                exceptions.Enqueue(ex);
            }
        });

        Assert.Empty(exceptions);
        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void Constructor_NormalizesHomeDirectory_ToFullPath()
    {
        // A home directory containing a redundant "." segment must normalize
        // (via Path.GetFullPath) to the same root as the clean path. The lazy
        // value factory must compute the identical normalized path the ctor
        // previously produced eagerly.
        var (service, _) = CreateService("Data/./Files");
        var expected = Path.GetFullPath(Path.Combine(_contentRoot, "Data", "Files"));

        Assert.Equal(expected, service.ResolveFullPath(""));
    }

    // =====================================================================
    // ResolveFullPath
    // =====================================================================

    [Fact]
    public void ResolveFullPath_Empty_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath(""));
    }

    [Fact]
    public void ResolveFullPath_Null_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath(null!));
    }

    [Fact]
    public void ResolveFullPath_Whitespace_ReturnsRoot()
    {
        var (service, root) = CreateService();

        Assert.Equal(root, service.ResolveFullPath("   "));
    }

    [Fact]
    public void ResolveFullPath_RelativePath_CombinesWithRoot()
    {
        var (service, root) = CreateService();

        var resolved = service.ResolveFullPath(Path.Combine("docs", "a.txt"));

        Assert.Equal(Path.GetFullPath(Path.Combine(root, "docs", "a.txt")), resolved);
        Assert.StartsWith(root + Path.DirectorySeparatorChar, resolved);
    }

    [Theory]
    [InlineData("../escape")]
    [InlineData("../../escape")]
    [InlineData("/etc/passwd")]
    public void ResolveFullPath_PathOutsideRoot_ThrowsArgumentException(string path)
    {
        var (service, _) = CreateService();

        var ex = Assert.Throws<ArgumentException>(() => service.ResolveFullPath(path));
        Assert.Equal("Invalid path", ex.Message);
    }

    [Fact]
    public void ResolveFullPath_DotDotThatStaysInsideRoot_Resolves()
    {
        var (service, root) = CreateService();
        Directory.CreateDirectory(Path.Combine(root, "docs"));

        // "docs/../a.txt" normalizes back inside the root and must be allowed.
        var resolved = service.ResolveFullPath("docs/../a.txt");

        Assert.Equal(Path.GetFullPath(Path.Combine(root, "a.txt")), resolved);
    }

    // =====================================================================
    // Browse
    // =====================================================================

    [Fact]
